import { db } from './config.js';
import { ref, update } from "https://www.gstatic.com/firebasejs/10.8.1/firebase-database.js";

window.encodeImageFileAsURLAbout = async function(element) { let file = element.files[0]; if(!file) return; Swal.showLoading(); try { let url = await window.uploadImageToGitHub(file); document.getElementById('swal-img-b64-about').value = ''; document.getElementById('swal-about-img').value = url; if(document.getElementById('preview-about-img')) document.getElementById('preview-about-img').src = url; } catch(e) { Swal.showValidationMessage(e); } Swal.hideLoading(); };
window.encodeImageFileAsURL = async function(element) { let file = element.files[0]; if(!file) return; Swal.showLoading(); try { let url = await window.uploadImageToGitHub(file); if(document.getElementById('swal-img-b64')) document.getElementById('swal-img-b64').value = ''; if(document.getElementById('swal-img')) document.getElementById('swal-img').value = url; if(document.getElementById('swal-f-logo')) document.getElementById('swal-f-logo').value = url; } catch(e) { Swal.showValidationMessage(e); } Swal.hideLoading(); };
window.encodeImageFileAsURLAct = async function(element) { let file = element.files[0]; if(!file) return; Swal.showLoading(); try { let url = await window.uploadImageToGitHub(file); document.getElementById('swal-img-b64-act').value = ''; document.getElementById('swal-img-act').value = url; if(document.getElementById('preview-act-img')) document.getElementById('preview-act-img').src = url; } catch(e) { Swal.showValidationMessage(e); } Swal.hideLoading(); };
window.encodeImageFileAsURLActAdd = async function(element) { let file = element.files[0]; if(!file) return; Swal.showLoading(); try { let url = await window.uploadImageToGitHub(file); document.getElementById('swal-img-b64-act-add').value = ''; document.getElementById('swal-img-act-add').value = url; if(document.getElementById('preview-act-add-wrapper')) { document.getElementById('preview-act-add-wrapper').classList.remove('d-none'); document.getElementById('preview-act-add-img').src = url; } } catch(e) { Swal.showValidationMessage(e); } Swal.hideLoading(); };

window.cmsEditContactForm = async () => {
    let cd = window.cmsData.contact_data || { phone: "028 7308 3333 (Phím 0)", messenger: "#", bgColor: "#4db8ff", btnSubmitBg: "#b86b62", btnMesBg: "#416f94", btnPhoneBg: "#ba5d6f" };
    let htmlForm = `
        <div class="alert alert-info text-start small mb-3">Cấu hình thông tin và màu sắc cho khối Liên Hệ cuối trang.</div>
        <div class="row g-3 text-start px-2">
            <div class="col-md-6"><label class="fw-bold small mb-1">SĐT hiển thị:</label><input id="swal-cf-phone" class="form-control form-control-sm" value="${cd.phone}"></div>
            <div class="col-md-6"><label class="fw-bold small mb-1">Link Messenger / Zalo:</label><input id="swal-cf-messenger" class="form-control form-control-sm" value="${cd.messenger}"></div>
            <div class="col-md-6 mt-4"><label class="fw-bold small mb-1 text-primary">Màu nền 2 khung lớn:</label><input type="color" id="swal-cf-bg" class="form-control form-control-color form-control-sm w-100 p-0" value="${cd.bgColor || '#4db8ff'}"></div>
            <div class="col-md-6 mt-4"><label class="fw-bold small mb-1 text-danger">Màu nút TƯ VẤN NGAY:</label><input type="color" id="swal-cf-btn-submit" class="form-control form-control-color form-control-sm w-100 p-0" value="${cd.btnSubmitBg || '#b86b62'}"></div>
            <div class="col-md-6"><label class="fw-bold small mb-1 text-info">Màu nút NHẮN TIN:</label><input type="color" id="swal-cf-btn-mes" class="form-control form-control-color form-control-sm w-100 p-0" value="${cd.btnMesBg || '#416f94'}"></div>
            <div class="col-md-6"><label class="fw-bold small mb-1 text-success">Màu nút SĐT Gọi:</label><input type="color" id="swal-cf-btn-phone" class="form-control form-control-color form-control-sm w-100 p-0" value="${cd.btnPhoneBg || '#ba5d6f'}"></div>
        </div>
    `;
    const { value: vals } = await Swal.fire({ title: 'Tùy Chỉnh Khối Liên Hệ', width: '700px', html: htmlForm, showCancelButton: true, confirmButtonText: 'Lưu thay đổi', cancelButtonText: 'Hủy', preConfirm: () => { return { phone: document.getElementById('swal-cf-phone').value, messenger: document.getElementById('swal-cf-messenger').value, bgColor: document.getElementById('swal-cf-bg').value, btnSubmitBg: document.getElementById('swal-cf-btn-submit').value, btnMesBg: document.getElementById('swal-cf-btn-mes').value, btnPhoneBg: document.getElementById('swal-cf-btn-phone').value } } });
    if(vals) { window.cmsData.contact_data = vals; await update(ref(db, 'pageContent'), { contact_data: vals }); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã lưu thành công!', showConfirmButton:false, timer:2000}); }
};

window.cmsEditAbout = async () => {
    let ab = window.cmsData.about_data || {};
    const { value: vals } = await Swal.fire({
        title: 'Sửa Khối Ảnh & Chữ', width: '800px',
        html: `<div class="row"><div class="col-md-5"><label class="fw-bold small text-start d-block mb-1">Ảnh bên trái:</label><img id="preview-about-img" src="${ab.img || 'https://via.placeholder.com/600x400'}" style="width: 100%; border-radius: 8px; margin-bottom: 10px; object-fit: cover; aspect-ratio: 16/10;"><input id="swal-about-img" class="form-control form-control-sm mb-2" placeholder="Dán link ảnh..." value="${ab.img || ''}"><input type="file" class="form-control form-control-sm mb-3" accept="image/*" onchange="encodeImageFileAsURLAbout(this)"><input type="hidden" id="swal-img-b64-about" value=""></div><div class="col-md-7 text-start"><label class="fw-bold small mb-1">Tiêu đề (cột phải):</label><input id="swal-about-title" class="form-control mb-3 fw-bold" value="${ab.title || ''}" placeholder="Nhập tiêu đề..."><label class="fw-bold small mb-1">Nội dung văn bản:</label><div class="editor-toolbar bg-light border p-1 mb-1 d-flex gap-1 flex-wrap rounded"><button type="button" class="btn btn-sm btn-outline-dark fw-bold" onmousedown="event.preventDefault();" onclick="document.execCommand('bold', false, '');">B</button><button type="button" class="btn btn-sm btn-outline-dark fst-italic" onmousedown="event.preventDefault();" onclick="document.execCommand('italic', false, '');">I</button><button type="button" class="btn btn-sm btn-outline-dark text-decoration-underline" onmousedown="event.preventDefault();" onclick="document.execCommand('underline', false, '');">U</button><div class="vr mx-1"></div><button type="button" class="btn btn-sm btn-outline-dark" onmousedown="event.preventDefault();" onclick="document.execCommand('justifyLeft', false, '');"><i class="bi bi-text-left"></i></button><button type="button" class="btn btn-sm btn-outline-dark" onmousedown="event.preventDefault();" onclick="document.execCommand('justifyCenter', false, '');"><i class="bi bi-text-center"></i></button><button type="button" class="btn btn-sm btn-outline-dark" onmousedown="event.preventDefault();" onclick="document.execCommand('justifyRight', false, '');"><i class="bi bi-text-right"></i></button><div class="vr mx-1"></div><button type="button" class="btn btn-sm btn-outline-danger" onmousedown="event.preventDefault();" onclick="document.execCommand('removeFormat', false, '');"><i class="bi bi-eraser"></i></button></div><div id="swal-about-desc" contenteditable="true" class="form-control" style="min-height: 150px; max-height: 250px; overflow-y: auto;">${ab.desc || ''}</div></div></div><div class="row mt-3 text-start"><div class="col-4"><label class="fw-bold small">Màu nền khối:</label><input type="color" id="swal-about-bg" value="${ab.bgColor || '#ffffff'}" class="form-control form-control-color form-control-sm w-100 p-0"></div><div class="col-4"><label class="fw-bold small">Màu tiêu đề:</label><input type="color" id="swal-about-title-color" value="${ab.titleColor || '#112255'}" class="form-control form-control-color form-control-sm w-100 p-0"></div><div class="col-4"><label class="fw-bold small">Màu chữ nội dung:</label><input type="color" id="swal-about-desc-color" value="${ab.descColor || '#475569'}" class="form-control form-control-color form-control-sm w-100 p-0"></div></div>`,
        showCancelButton: true, confirmButtonText: 'Lưu thay đổi', cancelButtonText: 'Hủy', preConfirm: () => { let b64 = document.getElementById('swal-img-b64-about').value; let url = document.getElementById('swal-about-img').value; return { img: b64 ? b64 : url, title: document.getElementById('swal-about-title').value, desc: document.getElementById('swal-about-desc').innerHTML, bgColor: document.getElementById('swal-about-bg').value, titleColor: document.getElementById('swal-about-title-color').value, descColor: document.getElementById('swal-about-desc-color').value } }
    });
    if(vals) { window.cmsData.about_data = vals; await update(ref(db, 'pageContent/about_data'), vals); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã lưu!', showConfirmButton:false, timer:2000}); }
};

window.cmsEditActivityTitle = async () => { const { value: title } = await Swal.fire({ title: 'Sửa Tiêu Đề', input: 'text', inputValue: window.cmsData.activity_data.title, showCancelButton: true }); if(title) { window.cmsData.activity_data.title = title; await update(ref(db, 'pageContent/activity_data'), window.cmsData.activity_data); } };
window.swalDelAct = async (idx) => { Swal.fire({ title: 'Xóa ảnh này?', icon: 'warning', showCancelButton: true }).then(async (r) => { if(r.isConfirmed) { window.cmsData.activity_data.slides.splice(idx, 1); await update(ref(db, 'pageContent/activity_data'), window.cmsData.activity_data); let newList = ''; window.cmsData.activity_data.slides.forEach((s, i) => { newList += `<tr><td>${i+1}</td><td class="text-start"><img src="${s.img}" style="width:30px; height:30px; object-fit:cover;" class="me-1 border rounded"><span class="small">${s.text ? s.text.substring(0, 20)+'...' : ''}</span></td><td><button type="button" class="btn btn-sm btn-danger py-0 px-1" onclick="window.swalDelAct(${i})"><i class="bi bi-trash"></i></button></td></tr>`; }); document.getElementById('swal-act-tbody').innerHTML = newList; } }); };
window.cmsAddActivitySlide = async () => {
    let listHTML = ''; if(window.cmsData.activity_data.slides) window.cmsData.activity_data.slides.forEach((s, i) => { listHTML += `<tr><td>${i+1}</td><td class="text-start"><img src="${s.img}" style="width:30px; height:30px; object-fit:cover;" class="me-1 border rounded"><span class="small">${s.text ? s.text.substring(0, 20)+'...' : ''}</span></td><td><button type="button" class="btn btn-sm btn-danger py-0 px-1" onclick="window.swalDelAct(${i})"><i class="bi bi-trash"></i></button></td></tr>`; });
    let htmlFull = `<div class="row m-0"><div class="col-md-6 border-end p-0"><div class="text-start pe-2"><div class="text-center mb-2 d-none" id="preview-act-add-wrapper"><img id="preview-act-add-img" src="" style="max-height: 100px; border-radius: 8px; object-fit: cover;"></div><label class="fw-bold mb-1 small">Link Ảnh HOẶC Tải ảnh từ máy:</label><input id="swal-img-act-add" class="form-control form-control-sm mb-2" placeholder="Dán link ảnh..."><input id="swal-img-file-act-add" type="file" class="form-control form-control-sm mb-2" accept="image/*" onchange="encodeImageFileAsURLActAdd(this)"><input type="hidden" id="swal-img-b64-act-add" value=""><label class="fw-bold mb-1 small">Nội dung (chữ in nghiêng):</label><textarea id="swal-text-act-add" class="form-control form-control-sm" style="height:80px;" placeholder="Nhập nội dung..."></textarea></div></div><div class="col-md-6 p-0"><div class="text-start ps-2" style="max-height: 300px; overflow-y: auto;"><label class="fw-bold mb-2 text-primary small">Dữ liệu hiện tại:</label><table class="table table-sm table-bordered table-hover"><thead class="table-light"><tr><th style="width:40px;">STT</th><th>Nội dung</th><th style="width:40px;">Xóa</th></tr></thead><tbody id="swal-act-tbody">${listHTML}</tbody></table></div></div></div>`;
    const { value: vals } = await Swal.fire({ title: 'Quản Lý Ảnh Hoạt Động', width: '800px', html: htmlFull, showCancelButton: true, confirmButtonText: 'Thêm mới', preConfirm: () => { let b64 = document.getElementById('swal-img-b64-act-add').value; let url = document.getElementById('swal-img-act-add').value; let finalImg = b64 ? b64 : url; if (!finalImg) { Swal.showValidationMessage('Vui lòng chọn ảnh!'); return false; } return { img: finalImg, text: document.getElementById('swal-text-act-add').value }; } });
    if(vals) { if(!window.cmsData.activity_data.slides) window.cmsData.activity_data.slides = []; window.cmsData.activity_data.slides.push(vals); await update(ref(db, 'pageContent/activity_data'), window.cmsData.activity_data); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã thêm!', showConfirmButton:false, timer:2000}); }
};
window.cmsEditActivitySlide = async (i) => {
    let slide = window.cmsData.activity_data.slides[i];
    const { value: vals } = await Swal.fire({ title: 'Sửa Ảnh & Nội Dung', html: `<div class="text-center mb-3"><label class="fw-bold d-block mb-2 text-primary">Ảnh hiện tại:</label><img id="preview-act-img" src="${slide.img}" style="max-height: 120px; border-radius: 8px; object-fit: cover;"></div><div class="mb-2 text-start mt-3"><label class="fw-bold">Thay thế (Dán Link HOẶC Tải ảnh mới):</label></div><input id="swal-img-act" class="swal2-input mt-0 mb-2" placeholder="Dán link ảnh..." value="${slide.img || ''}"><input id="swal-img-file-act" type="file" class="form-control w-75 mx-auto mb-3" accept="image/*" onchange="encodeImageFileAsURLAct(this)"><input type="hidden" id="swal-img-b64-act" value=""><div class="text-start mt-3"><label class="fw-bold">Nội dung (chữ in nghiêng):</label></div><textarea id="swal-text-act" class="swal2-textarea mt-0" placeholder="Nhập nội dung...">${slide.text || ''}</textarea>`, showCancelButton: true, preConfirm: () => { let b64 = document.getElementById('swal-img-b64-act').value; let url = document.getElementById('swal-img-act').value; return { img: b64 ? b64 : url, text: document.getElementById('swal-text-act').value }; } });
    if(vals) { window.cmsData.activity_data.slides[i] = vals; await update(ref(db, 'pageContent/activity_data'), window.cmsData.activity_data); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã lưu!', showConfirmButton:false, timer:2000}); }
};
window.cmsDeleteActivityBlock = async () => { Swal.fire({ title: 'Xóa vĩnh viễn khối này?', text: 'Khối Hình Ảnh Hoạt Động sẽ bị xóa đi.', icon: 'warning', showCancelButton: true }).then(async (r) => { if (r.isConfirmed) { window.cmsData.activity_data.isDeleted = true; await update(ref(db, 'pageContent/activity_data'), window.cmsData.activity_data); Swal.fire('Đã xóa', '', 'success'); } }); };

window.cmsToggleVis = async (key) => { let cur = window.cmsData.visibility ? window.cmsData.visibility[key] : true; await update(ref(db, 'pageContent/visibility'), { [key]: !cur }); };
window.cmsToggleVisBlock = async (bIndex) => { window.cmsData.custom_blocks[bIndex].isHidden = !window.cmsData.custom_blocks[bIndex].isHidden; await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); };
window.cmsDeleteBlock = async (bIndex) => { Swal.fire({title:'Xóa vĩnh viễn khối này?', icon:'warning', showCancelButton:true}).then(async (r)=>{ if(r.isConfirmed) { window.cmsData.custom_blocks.splice(bIndex, 1); await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); } }); };

window.selectIcon = function(iconClass, event) { document.querySelectorAll('.icon-option').forEach(el => el.classList.remove('border-primary', 'border-3')); event.currentTarget.classList.add('border-primary', 'border-3'); document.getElementById('swal-icon').value = iconClass; }
window.toSlug = (str) => { return str.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/đ/g, 'd').replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, ''); };

window.cmsEditBlockTitle = async (bIndex) => { 
    let block = window.cmsData.custom_blocks[bIndex];
    let htmlForm = `
        <div class="text-start mb-3"><label class="fw-bold small mb-1">Tiêu đề khối:</label><input id="swal-bt-title" class="form-control" placeholder="Nhập tiêu đề..." value="${block.title||''}" oninput="document.getElementById('swal-bt-slug').value = window.toSlug(this.value)"></div>
        <div class="text-start mb-3"><label class="fw-bold small mb-1">Mã điểm neo (Anchor ID để làm link nhảy vùng):</label><div class="input-group"><span class="input-group-text">#</span><input id="swal-bt-slug" class="form-control" placeholder="viet-lien-khong-dau" value="${block.slug || window.toSlug(block.title || '')}"></div><small class="text-muted d-block mt-1">VD: Đặt là <b class="text-danger">khoicongnghe</b>, tạo menu trỏ đến link <b class="text-primary">#khoicongnghe</b> để web tự cuộn xuống.</small></div>
    `;
    if(block.type === 'tech' || block.type === 'english' || block.type === 'news') {
        if(block.type !== 'news') {
            let iconsArr = ['bi-card-checklist', 'bi-robot', 'bi-controller', 'bi-laptop', 'bi-book', 'bi-brush', 'bi-code', 'bi-globe', 'bi-lightning', 'bi-palette', 'bi-rocket', 'bi-star'];
            let currentIcon = block.icon || (block.type==='tech'?'bi-card-checklist':'bi-book');
            htmlForm += `<div class="mb-2 text-start mt-3"><label class="fw-bold small">Chọn Icon cho Tiêu đề:</label></div><div id="icon-picker" class="d-flex flex-wrap gap-2 mb-3 justify-content-center p-2 rounded bg-light border">` + iconsArr.map(i => `<i class="bi ${i} fs-3 p-2 border rounded bg-white icon-option ${currentIcon === i ? 'border-primary border-3' : ''}" style="cursor:pointer;" onclick="window.selectIcon('${i}', event)"></i>`).join('') + `</div><input type="hidden" id="swal-icon" value="${currentIcon}">`;
        }
        htmlForm += `<div class="mt-3 text-start"><label class="fw-bold small">Màu sắc Tiêu đề / Viền khối:</label><input type="color" id="swal-bt-color" value="${block.color || (block.type==='tech'?'#f15a3a':(block.type==='news'?'#ff9800':'#112255'))}" class="form-control form-control-color w-100"></div>`;
        if(block.type !== 'news') { htmlForm += `<div class="mt-3 text-start"><label class="fw-bold small">Màu nền toàn khối:</label><input type="color" id="swal-bt-bg" value="${block.bgColor || (block.type==='tech'?'transparent':'#ffffff')}" class="form-control form-control-color w-100"></div>`; }
    }
    const { value: vals } = await Swal.fire({ title: 'Đổi Thuộc Tính Khối & Điểm Neo', html: htmlForm, showCancelButton: true, confirmButtonText: 'Lưu cấu hình', preConfirm: () => { let res = { title: document.getElementById('swal-bt-title').value, slug: document.getElementById('swal-bt-slug').value.toLowerCase().replace(/[^a-z0-9\-]/g, '') }; if(document.getElementById('swal-icon')) res.icon = document.getElementById('swal-icon').value; if(document.getElementById('swal-bt-color')) res.color = document.getElementById('swal-bt-color').value; if(document.getElementById('swal-bt-bg')) res.bgColor = document.getElementById('swal-bt-bg').value; return res; } }); 
    if (vals) { window.cmsData.custom_blocks[bIndex].title = vals.title; window.cmsData.custom_blocks[bIndex].slug = vals.slug; if(vals.icon) window.cmsData.custom_blocks[bIndex].icon = vals.icon; if(vals.color) window.cmsData.custom_blocks[bIndex].color = vals.color; if(vals.bgColor) window.cmsData.custom_blocks[bIndex].bgColor = vals.bgColor; await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã lưu!', showConfirmButton:false, timer:2000}); } 
};

window.cmsEditSlug = async (bIndex) => {
    let block = window.cmsData.custom_blocks[bIndex];
    const { value: newSlug } = await Swal.fire({ title: 'Sửa Mã Điểm Neo', input: 'text', inputPlaceholder: 'vd: khoicongnghe', inputValue: block.slug || '', showCancelButton: true, confirmButtonText: 'Lưu thay đổi', text: 'Mã này dùng để làm Menu nhảy đến khối. Viết liền không dấu.', preConfirm: (val) => { return window.toSlug(val); } });
    if (newSlug !== undefined) { window.cmsData.custom_blocks[bIndex].slug = newSlug; await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã lưu!', showConfirmButton:false, timer:2000}); }
};

window.allowDrop = (ev) => { ev.preventDefault(); ev.currentTarget.classList.add('dragover'); }; window.dragLeave = (ev) => { ev.currentTarget.classList.remove('dragover'); }; window.dragBlock = (ev, type) => { ev.dataTransfer.setData("text/plain", type); };

window.createNewBlockObj = (type, dropPos) => {
    let timestamp = Date.now(); let newBlock = { id: timestamp, isHidden: false, pos: dropPos || 'pos-bottom', slug: 'khoi-' + timestamp };
    if (type === "box-text") { newBlock = { ...newBlock, type: 'text', title: 'Hộp Văn Bản Mới', slug: 'khoi-van-ban-' + timestamp, content: "<div class='text-center'><h2 style='color: #112255; font-weight: 800; font-size: 32px; margin-bottom: 15px;'>Tiêu Đề Box Mới</h2><p style='font-size: 18px; color: #64748b; max-width: 800px; margin: 0 auto; line-height: 1.6;'>Đây là nội dung văn bản. Nhấn Sửa Box ở thanh công cụ xanh phía trên để sử dụng trình soạn thảo.</p></div>", bgColor: "#ffffff", textColor: "#333333", isTransparent: true, hasShadow: false }; } 
    else if (type === "tech-list") { newBlock = { ...newBlock, type: 'tech', title: 'Khối Thông Tin 1', slug: 'khoicongnghe', color: '#f15a3a', icon: 'bi-card-checklist', cards: [{ img: "", title: "", desc: "", color: "#00d5ff", icon: "bi-robot", has_detail: false, detail_bg: "#112255" }] }; } 
    else if (type === "english-list") { newBlock = { ...newBlock, type: 'english', title: 'Khối Thông Tin 2', slug: 'khoitienganh', color: '#112255', icon: 'bi-book', bgColor: "#ffffff", cards: [{ img: "", title: "", age: "", desc: "", bg_color: "#ffffff", text_color: "#233066", has_detail: false, detail_bg: "#112255" }] }; }
    else if (type === "teacher-list") { newBlock = { ...newBlock, type: 'teacher', title: 'Đội Ngũ Giảng Viên Mới', slug: 'khoigiaovien', icon: 'bi-person-video3', color: '#1d73dd', cards: [{ img: "", name: "", role: "", experience: "", hideExperience: false, nameColor: "#112255", roleColor: "#112255", bgColor: "#1d73dd" }] }; }            
    else if (type === "news-list") { newBlock = { ...newBlock, type: 'news', title: 'LLC NEWS MỚI', slug: 'khoitintuc', color: '#ff9800', slides: [{ img: "https://via.placeholder.com/800x600?text=News+Image+1" }] }; }
    return newBlock;
};

window.processAddBlock = async (type, dropPos) => {
    if(!window.cmsData.custom_blocks) window.cmsData.custom_blocks = []; var bsOffcanvas = bootstrap.Offcanvas.getInstance(document.getElementById('toolSidebar')); if (bsOffcanvas) bsOffcanvas.hide();
    if(type) { let newBlock = window.createNewBlockObj(type, dropPos); let firstIndex = window.cmsData.custom_blocks.findIndex(b => b.pos === (dropPos || 'pos-bottom')); if(firstIndex !== -1) window.cmsData.custom_blocks.splice(firstIndex, 0, newBlock); else window.cmsData.custom_blocks.push(newBlock); await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã thêm khối mới!', showConfirmButton:false, timer:2000}); }
};

window.addBlockClick = async (type) => { const { value: dropPos } = await Swal.fire({ title: 'Chọn khu vực chèn khối', input: 'select', inputOptions: { 'pos-top': 'Khu vực 1: Dưới Ảnh Bìa', 'pos-mid1': 'Khu vực 2: Dưới Khám phá', 'pos-mid2': 'Khu vực 3: Dưới Khối TT1', 'pos-bottom': 'Khu vực 4: Dưới Khối TT2' }, inputPlaceholder: 'Bấm chọn vùng...', showCancelButton: true, confirmButtonText: 'Chèn khối' }); if (dropPos) await window.processAddBlock(type, dropPos); };
window.dropHandler = async (ev, dropPos) => { ev.preventDefault(); ev.currentTarget.classList.remove('dragover'); let type = ev.dataTransfer.getData("text/plain"); if(type) await window.processAddBlock(type, dropPos); };
window.dropHandlerBetween = async (ev, bIndex) => { ev.preventDefault(); ev.currentTarget.classList.remove('dragover'); let type = ev.dataTransfer.getData("text/plain"); if(type) { var bsOffcanvas = bootstrap.Offcanvas.getInstance(document.getElementById('toolSidebar')); if (bsOffcanvas) bsOffcanvas.hide(); let pos = window.cmsData.custom_blocks[bIndex].pos; let newBlock = window.createNewBlockObj(type, pos); window.cmsData.custom_blocks.splice(bIndex + 1, 0, newBlock); await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); Swal.fire({toast:true, position:'top-end', icon:'success', title:'Đã chèn khối vào giữa!', showConfirmButton:false, timer:2000}); } };

window.cmsAddCard = async (type, blockIndex) => { let newCard = type === 'tech' ? { img: "", title: "", desc: "", color: "#000000", icon: "bi-star", has_detail: false, detail_bg: "#112255" } : { img: "", title: "", age: "", desc: "", bg_color: "#ffffff", text_color: "#000000", has_detail: false, detail_bg: "#112255" }; if(blockIndex !== null) { if(!window.cmsData.custom_blocks[blockIndex].cards) window.cmsData.custom_blocks[blockIndex].cards = []; window.cmsData.custom_blocks[blockIndex].cards.push(newCard); await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); } };
window.cmsDeleteCard = async (type, index, blockIndex) => { Swal.fire({ title: 'Xóa thẻ này?', icon: 'warning', showCancelButton: true }).then(async (r) => { if(r.isConfirmed) { if(blockIndex !== null) { window.cmsData.custom_blocks[blockIndex].cards.splice(index, 1); await update(ref(db, 'pageContent'), { custom_blocks: window.cmsData.custom_blocks }); } } }); };

window.applyFontSizeDetail = (size) => { document.execCommand("fontSize", false, "7"); let fontElements = document.getElementById('swal-detail-content').getElementsByTagName("font"); for (let i = 0; i < fontElements.length; ++i) { if (fontElements[i].size == "7") { fontElements[i].removeAttribute("size"); fontElements[i].style.fontSize = size; } } };
window.toggleDetailFullscreen = () => { const container = document.getElementById('detail-editor-container'); const editor = document.getElementById('swal-detail-content'); if(container.classList.contains('fullscreen-editor')) { container.classList.remove('fullscreen-editor'); editor.style.maxHeight = '300px'; editor.style.minHeight = '150px'; } else { container.classList.add('fullscreen-editor'); editor.style.maxHeight = 'none'; editor.style.minHeight = '60vh'; } };
window.insertDetailImage = async () => { const { value: url } = await Swal.fire({ title: 'Chèn ảnh', html: `<input id="swal-detail-img" class="swal2-input mt-0 mb-2" placeholder="Dán link ảnh vào đây..."><label class="fw-bold small d-block text-start mb-1 px-4">Hoặc tải ảnh từ PC:</label><input type="file" class="form-control w-75 mx-auto" accept="image/*" onchange="window.handleSimpleUpload(this, 'swal-detail-img')">`, showCancelButton: true, preConfirm: () => document.getElementById('swal-detail-img').value }); if (url) { document.getElementById('swal-detail-content').focus(); document.execCommand('insertHTML', false, `<div style="text-align: center; margin: 15px 0;"><img src="${url}" style="max-width: 100%; border-radius: 8px;" class="detail-editable-img" title="Click đúp để thêm ghi chú"></div><p><br></p>`); } };
window.handleDetailImgDblClick = async (e) => { if(e.target.tagName === 'IMG') { const { value: caption } = await Swal.fire({ title: 'Thêm ghi chú ảnh', input: 'text', inputPlaceholder: 'Nhập nội dung ghi chú...', showCancelButton: true }); if (caption) { let parent = e.target.parentElement; let existingCap = parent.querySelector('i.img-caption'); if (existingCap) existingCap.remove(); let capHtml = document.createElement('i'); capHtml.className = 'img-caption d-block mt-2 text-muted'; capHtml.innerText = caption; if(parent.tagName === 'DIV') { parent.appendChild(capHtml); } else { let wrapper = document.createElement('div'); wrapper.style.textAlign = 'center'; wrapper.style.margin = '15px 0'; parent.insertBefore(wrapper, e.target); wrapper.appendChild(e.target); wrapper.appendChild(capHtml); } } } };

