        let iconGrid = `<div class="mb-2 text-start mt-3"><label class="fw-bold">Chọn Icon cho thẻ:</label></div><div id="icon-picker" class="d-flex flex-wrap gap-2 mb-3 justify-content-center p-2 rounded bg-light border">` + iconsArr.map(i => `<i class="bi ${i} fs-3 p-2 border rounded bg-white icon-option ${card.icon === i ? 'border-primary border-3' : ''}" style="cursor:pointer;" onclick="selectIcon('${i}', event)"></i>`).join('') + `</div><input type="hidden" id="swal-icon" value="${card.icon || 'bi-cpu'}">`; 
